#include <stdio.h>
#include <string.h>
#include <ctype.h>
int main(){
    int T; char M[27];
    if(scanf("%d %26s", &T, M)!=2) return 0;
    getchar(); // consume newline after M
    char S[101];
    while(T--){
        if(!fgets(S,101,stdin)) break;
        S[strcspn(S,"\n")] = '\0';
        for(int i=0; S[i]; ++i){
            if(S[i]=='_') S[i]=' ';
            else if(islower(S[i])) S[i]=M[S[i]-'a'];
            else if(isupper(S[i])) S[i]=toupper(M[tolower(S[i])-'a']);
        }
        printf("%s\n", S);
    }
    return 0;
}

