import sys
data = sys.stdin.read().splitlines()
if not data: sys.exit()
first = data[0].split()
T = int(first[0])
M = first[1]
out_lines = []
idx = 1
for _ in range(T):
    s = data[idx]
    idx += 1
    res = []
    for ch in s:
        if ch == '_':
            res.append(' ')
        elif 'a' <= ch <= 'z':
            res.append(M[ord(ch)-97])
        elif 'A' <= ch <= 'Z':
            res.append(M[ord(ch.lower())-97].upper())
        else:
            res.append(ch)
    out_lines.append(''.join(res))
sys.stdout.write('\n'.join(out_lines))

